import * as React from 'react';

const illustrationThemeContext = React.createContext('light');
const IllustrationThemeProvider = ({ children, mode = 'light', }) => React.createElement(illustrationThemeContext.Provider, { value: mode }, children);
const useIllustrationTheme = () => {
    return React.useContext(illustrationThemeContext);
};

export { IllustrationThemeProvider, IllustrationThemeProvider as default, illustrationThemeContext, useIllustrationTheme };
